"""Advanced RAG: HyDE, parent-child chunking, reranking pipeline."""
import os
import math
from openai import OpenAI
import chromadb

client = OpenAI(api_key=os.environ["OPENAI_API_KEY"])


# ── Embedding helper ─────────────────────────────────────────────
def embed(texts: list[str]) -> list[list[float]]:
    r = client.embeddings.create(model="text-embedding-3-small", input=texts)
    return [item.embedding for item in r.data]

def cosine_sim(a: list[float], b: list[float]) -> float:
    dot = sum(x * y for x, y in zip(a, b))
    ma  = math.sqrt(sum(x**2 for x in a))
    mb  = math.sqrt(sum(x**2 for x in b))
    return dot / (ma * mb) if ma and mb else 0.0


# ── 1. HyDE retrieval ────────────────────────────────────────────
class HyDERetriever:
    def __init__(self, vectorstore, k: int = 5):
        self.vs = vectorstore
        self.k  = k

    def _generate_hypothesis(self, query: str) -> str:
        response = client.chat.completions.create(
            model="gpt-4o-mini",
            messages=[{
                "role": "user",
                "content": f"Write a 2-3 sentence technical paragraph that would be the ideal answer to: {query}"
            }],
            temperature=0.0, max_tokens=200,
        )
        return response.choices[0].message.content

    def retrieve(self, query: str) -> list[dict]:
        hypothesis   = self._generate_hypothesis(query)
        hyp_emb      = embed([hypothesis])[0]
        query_emb    = embed([query])[0]

        # Retrieve with both and merge results
        hyp_results   = self.vs.retrieve(hyp_emb,   top_k=self.k)
        query_results = self.vs.retrieve(query_emb, top_k=self.k)

        # Deduplicate by chunk text, prefer higher score
        seen, merged = set(), []
        for r in hyp_results + query_results:
            key = r["text"][:50]
            if key not in seen:
                seen.add(key)
                merged.append(r)
        return sorted(merged, key=lambda x: -x["score"])[:self.k]


# ── 2. Cross-encoder reranker (pure Python, no sentence-transformers) ──
class LLMReranker:
    """Uses an LLM to score document relevance — production use Cohere rerank API."""
    def rerank(self, query: str, documents: list[dict], top_n: int = 5) -> list[dict]:
        if not documents:
            return []
        scores = []
        for doc in documents:
            response = client.chat.completions.create(
                model="gpt-4o-mini",
                messages=[{
                    "role": "user",
                    "content": f"Rate 0-10 how relevant this document is to the query.\nQuery: {query}\nDocument: {doc['text'][:300]}\nReturn only a number."
                }],
                temperature=0.0, max_tokens=5,
            )
            try:
                score = float(response.choices[0].message.content.strip())
            except ValueError:
                score = 0.0
            scores.append((score, doc))
        scores.sort(key=lambda x: -x[0])
        return [doc for _, doc in scores[:top_n]]


# ── 3. Parent-child chunking ──────────────────────────────────────
class ParentChildChunker:
    def __init__(self, parent_size: int = 800, child_size: int = 200, overlap: int = 20):
        self.parent_size = parent_size
        self.child_size  = child_size
        self.overlap     = overlap
        self._parent_map: dict[str, str] = {}  # child_id → parent_text

    def chunk(self, text: str, doc_id: str) -> list[dict]:
        # Split into parents
        parents = []
        for i in range(0, len(text), self.parent_size - self.overlap):
            parents.append(text[i:i + self.parent_size])

        # Split each parent into children
        children = []
        for p_idx, parent in enumerate(parents):
            for c_idx in range(0, len(parent), self.child_size - self.overlap):
                child_text = parent[c_idx:c_idx + self.child_size]
                child_id   = f"{doc_id}_p{p_idx}_c{c_idx}"
                self._parent_map[child_id] = parent
                children.append({"text": child_text, "id": child_id, "parent_text": parent})
        return children

    def get_parent(self, child_id: str) -> str | None:
        return self._parent_map.get(child_id)


# ── 4. Simple vector store for demo ──────────────────────────────
class SimpleVectorStore:
    def __init__(self):
        self._items: list[dict] = []

    def add(self, items: list[dict], embeddings: list[list[float]]) -> None:
        for item, emb in zip(items, embeddings):
            self._items.append({**item, "embedding": emb})

    def retrieve(self, query_emb: list[float], top_k: int = 10) -> list[dict]:
        scored = [(cosine_sim(query_emb, it["embedding"]), it) for it in self._items]
        scored.sort(key=lambda x: -x[0])
        return [{"text": it["text"], "score": s, "id": it.get("id", "")} for s, it in scored[:top_k]]


# ── 5. Advanced RAG pipeline ──────────────────────────────────────
class AdvancedRAGPipeline:
    def __init__(self):
        self.child_store  = SimpleVectorStore()
        self.chunker      = ParentChildChunker(parent_size=600, child_size=150)
        self.reranker     = LLMReranker()

    def index(self, documents: list[dict]) -> None:
        all_children = []
        for doc in documents:
            children = self.chunker.chunk(doc["text"], doc["doc_id"])
            all_children.extend(children)
        embeddings = embed([c["text"] for c in all_children])
        self.child_store.add(all_children, embeddings)
        print(f"Indexed {len(all_children)} child chunks from {len(documents)} documents")

    def query(self, question: str, use_hyde: bool = True, top_k_recall: int = 20, top_k_final: int = 3) -> dict:
        # Stage 1: Embed and retrieve children
        if use_hyde:
            hyp = client.chat.completions.create(
                model="gpt-4o-mini",
                messages=[{"role": "user", "content": f"Write a 2-sentence answer to: {question}"}],
                temperature=0.0, max_tokens=100,
            ).choices[0].message.content
            q_emb = embed([hyp])[0]
        else:
            q_emb = embed([question])[0]

        candidates = self.child_store.retrieve(q_emb, top_k=top_k_recall)

        # Stage 2: Upgrade to parent chunks
        parent_chunks = []
        seen_parents  = set()
        for c in candidates:
            parent = self.chunker.get_parent(c["id"]) or c["text"]
            if parent[:50] not in seen_parents:
                seen_parents.add(parent[:50])
                parent_chunks.append({"text": parent, "score": c["score"], "id": c["id"]})

        # Stage 3: Rerank parents
        reranked = self.reranker.rerank(question, parent_chunks, top_n=top_k_final)

        # Stage 4: Generate
        context = "\n\n".join(f"[{i+1}] {r['text']}" for i, r in enumerate(reranked))
        answer  = client.chat.completions.create(
            model="gpt-4o-mini",
            messages=[
                {"role": "system", "content": "Answer from context only. Cite [N]."},
                {"role": "user",   "content": f"Context:\n{context}\n\nQuestion: {question}"}
            ],
            temperature=0.0, max_tokens=500,
        ).choices[0].message.content
        return {"answer": answer, "chunks_retrieved": len(candidates), "chunks_used": len(reranked)}


if __name__ == "__main__":
    pipeline = AdvancedRAGPipeline()
    pipeline.index([
        {"doc_id": "rag",   "text": "RAG retrieves relevant documents and uses them as context. It reduces hallucinations by grounding responses. The key insight: models generate more accurate answers when given evidence. RAG is dynamic — you update the knowledge base without retraining the model. Chunking strategy is critical: 400-512 tokens with 10-15% overlap works best for most corpora."},
        {"doc_id": "finetune", "text": "Fine-tuning trains a model on task-specific examples. It improves style consistency and domain vocabulary but does not reliably update factual knowledge. Cost: significant compute and labeled data required. Fine-tuning is best for format adherence, not knowledge updating."},
    ])
    result = pipeline.query("Why is chunking strategy important in RAG?")
    print(f"Answer: {result['answer']}")
    print(f"Retrieved {result['chunks_retrieved']} → used {result['chunks_used']}")

