def get_parent_chunks(retrieved_children: list[dict], parent_map: dict[str, str]) -> list[dict]:
    seen_parents = set()
    parent_chunks = []
    for child in retrieved_children:
        child_id = child.get('id', '')
        parent_text = parent_map.get(child_id)
        if parent_text is None:
            parent_text = child['text']  # fallback to child if no parent
        parent_key = parent_text[:100]  # use first 100 chars as dedup key
        if parent_key not in seen_parents:
            seen_parents.add(parent_key)
            parent_chunks.append({'text': parent_text, 'score': child['score'], 'child_id': child_id})
    return parent_chunks
